solution_code:
#include <iostream>

int main() {
    int code;
    std::cin >> code;

    switch (code) {
        case 200:
            std::cout << "OK\n";
            break;
        case 301:
            std::cout << "Moved Permanently\n";
            break;
        case 302:
            std::cout << "Found\n";
            break;
        case 404:
            std::cout << "Not Found\n";
            break;
        case 500:
            std::cout << "Internal Server Error\n";
            break;
        default:
            std::cout << "Unknown\n";
            break;
    }

    return 0;
}

