solution_code:
#include <iostream>

void printPermissions(int level) {
    switch (level) {
        case 3:
            std::cout << "Admin\n";
            [[fallthrough]];
        case 2:
            std::cout << "Write\n";
            [[fallthrough]];
        case 1:
            std::cout << "Read\n";
            break;
        default:
            break;
    }
}

int main() {
    int level;
    std::cin >> level;
    printPermissions(level);
    std::cout << "\n";
    return 0;
}
